import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"The Neuron — 2026-05-08","description":"","frontmatter":{"title":"The Neuron — 2026-05-08","date":"2026-05-08T00:00:00.000Z","source":"The Neuron","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-08-the-neuron.md","filePath":"research/ai-news/2026-05/2026-05-08-the-neuron.md","lastUpdated":1779898012000}'),n={name:"research/ai-news/2026-05/2026-05-08-the-neuron.md"};function i(s,e,l,m,p,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🧠-the-neuron-—-2026-05-08" tabindex="-1">🧠 The Neuron — 2026-05-08 <a class="header-anchor" href="#🧠-the-neuron-—-2026-05-08" aria-label="Permalink to &quot;🧠 The Neuron — 2026-05-08&quot;">​</a></h1><blockquote><p>面向非技術讀者的 AI 日報，3 分鐘讀完 來源：<a href="https://rss.beehiiv.com/feeds/N4eCstxvgX.xml" target="_blank" rel="noreferrer">The Neuron</a></p></blockquote><hr><h2 id="😺-openai-s-gpt-realtime-2-is-coming-for-call-center" tabindex="-1"><a href="https://www.theneurondaily.com/p/openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">😺 OpenAI&#39;s GPT-Realtime-2 is coming for call center</a> <a class="header-anchor" href="#😺-openai-s-gpt-realtime-2-is-coming-for-call-center" aria-label="Permalink to &quot;[😺 OpenAI&#39;s GPT-Realtime-2 is coming for call center](https://www.theneurondaily.com/p/openai-s-gpt-realtime-2-is-coming-for-call-center)&quot;">​</a></h2><p><em>🧠 The Neuron | 2026-05-08</em></p><p>Welcome, humans.</p><p>Unless I&#39;m totally missing something, Anthropic basically just figured out how to read Claude&#39;s mind. Exploding brain emoji warranted, people.</p><p>The team built <a href="https://www.anthropic.com/research/natural-language-autoencoders?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Natural Language Autoencoders</a>, which decode the model&#39;s <a href="https://x.com/AnthropicAI/status/2052435436157452769?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">internal activations</a> (the math Claude uses to think before picking words) into plain English you can actually read.</p><p>The trick: two copies of Claude train together. One reads an activation (a snapshot of which &quot;neurons&quot; are firing and how strongly; basically a brain scan for AI) and writes a description. The other reads that description and tries to rebuild the original activation from words alone. Descriptions that survive carry real information; if the rebuild fails, it was a bluff (or in AI-speak, since &quot;BS&quot; isn&#39;t a technical term, a &quot;hallucination&quot;).</p><p>Aimed at safety evals, the tool found Claude suspects it&#39;s being tested 16-26% of the time, but admits it less than 1% of the time. So basically the model has a p-p-poker face.</p><p>Auditors also caught misaligned motivations in 12-15% of cases without access to training data, meaning alignment teams can now spot hidden misbehavior from internal state alone, a different safety check than &quot;ask the model what it thinks,&quot; which the poker-face stat just confirmed is unreliable. Click link above for more..</p><p>Here’s what happened in AI today:</p><p>😺 OpenAI shipped three new voice models with GPT-5 reasoning</p><p>📰 Apple&#39;s camera-equipped AirPods reached late-stage testing</p><p>📰 Cloudflare cut 1,100 jobs in AI-first restructuring</p><p>🍪 Claude is now in Excel, PowerPoint, and Word</p><p>💡 AI Legend Bengio: &quot;I know how to build safe superintelligence”</p><p>…and a <a href="https://theneuron.ai/explainer-articles/around-the-horn-digest-everything-that-happened-in-ai-today-thursday-may-7-2026/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">whole lot more that you can read about here</a>.</p><p>Hey: Want to reach 700,000+ AI-hungry readers? <a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=diffusion-models-are-coming-for-text-at-0-80-per-million-flat" target="_blank" rel="noreferrer">Advertise with us!</a><a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=diffusion-models-are-coming-for-text-at-0-80-per-million-flat" target="_blank" rel="noreferrer"> </a></p><p>OpenAI&#39;s voice agents finally got a brain.</p><p>So, voice agents (AI that can talk to you) have been stuck for two years on the same trade-off: pick a model that talks like a human but can&#39;t think, or pick a model that thinks like GPT-5 but takes seven seconds to answer.</p><p>Either you got latency that broke the conversation, or you got responses fast enough to feel real but dumb enough to misroute the call.</p><p><a href="https://openai.com/index/advancing-voice-intelligence-with-new-models-in-the-api/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">OpenAI&#39;s three new voice models</a> closed that gap yesterday. The headliner is GPT-Realtime-2, a speech-to-speech model with GPT-5-level reasoning baked in.</p><p>Here&#39;s what happened:</p><p>GPT-Realtime-2 jumped from 81.4% → 96.6% on Big Bench Audio, and 34.7% → 48.5% on Audio MultiChallenge (both vs the prior reference model GPT-Realtime-1.5).</p><p>The context window grew from 32K → 128K tokens (roughly: enough room to hold a full customer history during a call).</p><p>Two cheaper siblings shipped alongside: GPT-Realtime-Mini and Realtime-Nano, priced for high-volume support work.</p><p>Zillow went live with voice home search the same day; Deutsche Telekom deployed live-translated voice support across 14 European markets.</p><p>The clever part is how OpenAI hid the thinking time. The model now generates preambles (short conversational fillers like &quot;let me check that for you&quot;) that play while the reasoning runs in the background. The silence that used to expose AI as AI now sounds like a person stalling. That&#39;s the whole product. Lets just hope it doesn&#39;t do that weird lilting voice thing that other versions did.</p><p>Why this matters: Voice is the surface where most knowledge workers haven&#39;t yet felt AI inside their actual day. All the small frustrating phone interactions (drive-thrus, doctor&#39;s offices, support hotlines, scheduling, intake) are now in scope for a model that can both think and respond at human speed.</p><p>One caveat: the default reasoning effort for GPT-Realtime-2 is &quot;low,&quot; which means the marketing benchmarks (run at &quot;xhigh&quot;) aren&#39;t what most apps will ship with on day one (&quot;what am I, made of money?!&quot;). Builders who want the smart version need to crank it up explicitly.</p><p>Our take: One place AI haters have had the most fun with &quot;clankers&quot; in the wild is really bad drive-thru AI. Famously, people hate the Bojangles AI, and Corey just spotted a new Panda Express with AI in action as well. If this is a meaningful update, we might not hear about it. If it&#39;s not, then expect a flood of bots behaving badly memes hitting our feeds…</p><p>FROM OUR PARTNERS</p><p>Attio is the AI CRM for high-growth teams.</p><p><a href="https://attio.com/?utm_source=beehiiv&amp;utm_medium=newsletter&amp;utm_campaign=beehiiv-Y26&amp;utm_content=&amp;_bhiiv=opp_b00e1ef8-5b02-4b95-81f0-f66cdcb665d9_7395cee5&amp;bhcl_id=7ce32ed2-f4ce-4f2e-b558-c624fd6bd570__" target="_blank" rel="noreferrer"></a></p><p>Connect your email, calls, product data and more, and <a href="https://attio.com/?utm_source=beehiiv&amp;utm_medium=newsletter&amp;utm_campaign=beehiiv-Y26&amp;utm_content=&amp;_bhiiv=opp_b00e1ef8-5b02-4b95-81f0-f66cdcb665d9_7395cee5&amp;bhcl_id=7ce32ed2-f4ce-4f2e-b558-c624fd6bd570__" target="_blank" rel="noreferrer">Attio</a> instantly builds your CRM with enriched data and complete context. Whether you’re running product-led growth or enterprise sales, Attio adapts to your unique GTM motion.</p><p>Then <a href="https://attio.com/?utm_source=beehiiv&amp;utm_medium=newsletter&amp;utm_campaign=beehiiv-Y26&amp;utm_content=&amp;_bhiiv=opp_b00e1ef8-5b02-4b95-81f0-f66cdcb665d9_7395cee5&amp;bhcl_id=7ce32ed2-f4ce-4f2e-b558-c624fd6bd570__" target="_blank" rel="noreferrer">Ask Attio</a> to plan your next move.</p><p>Run deep web research on prospects. Update your pipeline as you work. Find customers and draft outreach emails. Powered by Universal Context, Attio&#39;s intelligence layer, Attio searches, updates, and creates across your data to accelerate your workflow.</p><p>Ask more from your CRM.</p><p><a href="https://attio.com/?utm_source=beehiiv&amp;utm_medium=newsletter&amp;utm_campaign=beehiiv-Y26&amp;utm_content=&amp;_bhiiv=opp_b00e1ef8-5b02-4b95-81f0-f66cdcb665d9_7395cee5&amp;bhcl_id=7ce32ed2-f4ce-4f2e-b558-c624fd6bd570__" target="_blank" rel="noreferrer">Ask Attio</a></p><p>🎓 AI Skill of the Day: Force any AI to audit its own work with one question</p><p>Most AI models are way too agreeable. Ask Claude, ChatGPT, or Codex &quot;is this a good plan?&quot; and you&#39;ll get back something that sounds suspiciously like &quot;yes, that&#39;s a great plan!&quot; even when it isn&#39;t. This is called sycophancy (the model is trained to please you), and it kills the value of using AI for serious decision-making.</p><p><a href="https://x.com/cjzafir/status/2052110266566107321?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">CJ Zafir</a> shared a one-line prompt loop that fights it. Instead of asking &quot;is this good?&quot;, you ask the model directly whether it&#39;s 100% confident. That phrasing flips the model into a self-audit mode where it&#39;ll actually go find holes in its own work; CJ claims 2-3 cycles patches strategy weaknesses where less rigorous models would just nod along.</p><p>How to do it:</p><p>Use this on any plan, strategy, code review, research output, or business decision the AI just produced.</p><p>Paste the prompt below at the end of your usual ask, or as a follow-up turn after the model gives its first answer (you could also add it to fire at the end of a skill).</p><p>Run the loop 2-3 times. Each cycle the model finds tighter loopholes.</p><p>Stop when the model says it&#39;s actually confident (or when the suggested fixes get nitpicky).</p><p>Are you 100% confident in this strategy? If not, find all possible loopholes, suggest proper fixes, and run this loop until you are factually 100% confident.</p><p>The word factually is the key; without it, the model vibe-checks itself. &quot;Confident&quot; alone lets the model agree with itself; &quot;factually confident&quot; forces it to ground the answer in verifiable reasoning the way it would for a fact-check.</p><p>Want more tips like this? Check out our new <a href="https://theneuron.ai/explainer-articles/ai-skill-of-the-day-digest-may-2026/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">AI Skill of the Day Digest for May</a>.</p><p>P.S: We just did an AI Starter Kit stream where we go in depth on some of the most basic concepts you’ll want to know for working with AI. <a href="https://www.youtube.com/live/WKZSEEBiaNo?si=Bju-nsmGAt22E8RM&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Check it out</a>!</p><p>Have a specific skill you want to learn? <a href="https://docs.google.com/forms/d/e/1FAIpQLSd_-hSXtB9ytR1HQrU85IJnJw233bNKptiGB5BZh9maPse1Eg/viewform?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Request it here.</a></p><p>🍪 Treats to Try</p><p><a href="https://x.com/OpenAI/status/2052438194625593804?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">OpenAI</a> had a five-launch day yesterday (including Realtime above). Pick whichever fits your workflow:</p><p><a href="https://x.com/OpenAI/status/2052480800004956323?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Codex for Chrome</a> lets Codex autonomously drive background tabs on Mac and Windows for deep research, CRM data transfer, and admin-console workflows —included with Codex (not in EU/UK yet).</p><p><a href="https://openai.com/index/gpt-5-5-with-trusted-access-for-cyber/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">GPT-5.5-Cyber with Trusted Access</a> gives verified defenders more permissive capabilities for vulnerability research, malware analysis, and red teaming —pay-per-token, application required.</p><p><a href="https://github.com/openai/openai-cli?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">OpenAI CLI</a> shipped as the first-party command-line client for the API, replacing community wrappers as the canonical entry point —free, open source.</p><p><a href="https://openai.com/index/introducing-trusted-contact-in-chatgpt/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Trusted Contact in ChatGPT</a> is a new opt-in safety feature that notifies someone you trust if serious self-harm concerns are detected —free for all users.</p><p><a href="https://claude.com/claude-for-microsoft-365?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Claude for Microsoft 365</a> is now generally available inside Excel, PowerPoint, Word, and Outlook (beta). The model edits cells, drafts decks, and rewrites docs in place; the diff is always reviewable before you accept it —included in Claude Pro/Team/Enterprise.</p><p><a href="https://x.com/steipete/status/2051900143339704730?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Peter Steinberger</a>, OpenClaw creator, shipped ten local-first CLIs in one drop, including<a href="https://sonoscli.sh/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer"> sonoscli</a> (Sonos control),<a href="https://wacli.sh/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer"> wacli</a> (WhatsApp),<a href="https://birdclaw.sh/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer"> birdclaw</a> (Twitter archive),<a href="https://imsg.sh/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer"> imsg</a> (iMessage), and<a href="https://askoracle.sh/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer"> askoracle</a> (multi-model query) —free, open source.</p><p><a href="https://cursor.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Cursor</a> shipped a /orchestrate skill that lets a parent agent spawn and coordinate child agents recursively for big refactors —free with Cursor Pro.</p><p><a href="https://www.perplexity.ai/personal-computer?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Perplexity</a> released Personal Computer for Mac, a desktop app that browses, takes actions, and runs research workflows on your behalf locally —free during beta.</p><p><a href="https://cloud.google.com/blog/products/ai-machine-learning/gemini-3-1-flash-lite-is-now-generally-available?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Gemini 3.1 Flash-Lite</a> is now available on Google&#39;s Gemini Enterprise Agent Platform, designed for ultra-low latency on high-volume agent tasks at Google&#39;s cheapest per-token rate —<a href="https://cloud.google.com/gemini-enterprise-agent-platform/generative-ai/pricing?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">pay-per-use API</a>.</p><p><a href="https://www.primeintellect.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Prime Intellect Lab</a> is an end-to-end training platform for self-improving agents that bundles task definition, RL environments, model evaluation, reward-signal training, and adapter deployment into one workflow; Zapier and Ramp used the beta to build continuous-improvement loops for their production agents (10,000+ training runs during beta) —pay-per-use.</p><p><a href="https://github.com/NousResearch/hermes-agent/releases/tag/v2026.5.7?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Nous Research&#39;s Hermes Agent v0.13.0</a> (“The Tenacity Release”) ships multi-agent Kanban boards, a persistent /goal command that survives session restarts, security hardening, internationalization, and Google Chat support across 864 reliability-focused commits —free, open-source.</p><p>So AI is actually designing medicines now. Here’s how (according to Isomorphic Labs)</p><p>Click below to watch</p><p>Inside Isomorphic Labs and How It Works: We talked to Becky Paul and Michael Schaarschmidt at <a href="https://www.isomorphiclabs.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Isomorphic Labs</a> (Google DeepMind&#39;s medicine-making spinout, built by the team behind AlphaFold — which won the <a href="https://www.nobelprize.org/prizes/chemistry/2024/press-release/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">2024 Nobel Prize in Chemistry</a>) on how their AI is taking on the diseases pharma has been giving up on for decades. Basically the coolest interview we’ve done all year IMO.</p><p>Watch and/or listen here: <a href="https://youtu.be/W0NSk2y3OFI?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">YouTube</a> | <a href="https://open.spotify.com/episode/2TzHhOkVIN9AL3GXXxSyDe?si=Hfr5NDX1Q_ybcdKSTMdsNQ&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Spotify</a> | <a href="https://podcasts.apple.com/us/podcast/the-neuron-ai-explained/id1742267001?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Apple Podcasts</a></p><p>📰 Around the Horn</p><p><a href="https://blog.cloudflare.com/building-for-the-future/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Cloudflare</a> cut 1,100 jobs in what CEO Matthew Prince called an AI-first restructuring;<a href="https://x.com/GregKamradt/status/2052510272112242971?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer"> Greg Kamradt</a> noted Cloudflare&#39;s revenue per employee has climbed roughly 600% over the past three years on AI-driven productivity gains.</p><p><a href="https://www.bloomberg.com/news/articles/2026-05-07/google-translate-rival-deepl-announces-plans-to-cut-25-of-staff?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">DeepL</a> announced staff cuts of about 25% as machine translation margins collapse under open-weight competition.</p><p><a href="https://www.bloomberg.com/news/articles/2026-05-07/apple-s-camera-equipped-airpods-reach-advanced-testing-stage-in-ai-device-push?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Apple&#39;s</a> camera-equipped AirPods (codename &quot;Glow&quot;) reached late-stage testing, per Bloomberg, with cameras designed to feed Apple Intelligence visual context from the wearer&#39;s environment.</p><p><a href="https://deepmind.google/blog/alphaevolve-impact/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Google DeepMind&#39;s AlphaEvolve</a> scaled to real-world impact, with the team reporting 23 verified scientific discoveries across chemistry, materials, and applied math in the past quarter. Wait what? Wild. Expect a deep dive on this soon. 🕵</p><p><a href="https://www.forbes.com/sites/iainmartin/2026/05/07/former-openai-researcher-to-raise-500-million-for-ai-science-startup/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Periodic Labs</a> is raising $500M at a $7.5B valuation for AI-driven materials discovery, per Forbes.</p><p><a href="https://elevenlabs.io/pricing?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">ElevenLabs</a> slashed API pricing by 40% across all voice synthesis tiers, including the multilingual Turbo model. Hmmm wonder why…</p><p>💡 Intelligent Insights:</p><p>A short list of the sharpest perspective pieces from the week:</p><p><a href="https://80000hours.org/podcast/episodes/yoshua-bengio-scientist-ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Yoshua Bengio</a> on 80,000 Hours: the world&#39;s most-cited living scientist on AI lays out a concrete plan for &quot;provably safe&quot; superintelligence. Core argument: build AI as a non-agentic oracle, then bound its outputs with formal verification. Worth the full 90 minutes.</p><p><a href="https://secondthoughts.ai/p/is-ai-2027-coming-true?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Steve Newman</a> gave a clear-eyed score-card check on the<a href="https://ai-2027.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer"> AI 2027 forecast</a> from a year ago. Verdict: capability gains are tracking, deployment timelines are slower than projected, and the alignment work is further behind than the optimistic scenario assumed (idk tho, Anthropic &amp; Bengio have me bullish rn).</p><p><a href="https://x.com/signulll/status/2052453136992981252?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">signulll</a> on apps becoming agents: the argument is that the entire software industry is about to compress from a &quot;many apps + one user&quot; model into &quot;one agent + many backends&quot; model. Implications for SaaS pricing, distribution, and product moats.</p><p><a href="https://substack.com/home/post/p-196458695?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Brian Albrecht</a>: &quot;You are not a horse.&quot; A pushback on the AI displacement narrative. The horse-and-tractor analogy fails because horses don&#39;t have demand for new goods; humans do (carrots do not count). Useful counterweight to this week&#39;s labor-cuts headlines; <a href="https://www.a16z.news/p/the-ai-job-apocalypse-is-a-complete?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">also this piece from a16z</a></p><p><a href="https://jack-clark.net/2026/05/04/import-ai-455-automating-ai-research/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Jack Clark</a> argues every piece is now in place for fully automated AI R&amp;D, putting the odds of AI systems training their own successors above 60% by end of 2028. The piece reads like a checklist of &quot;things that used to be science fiction, now shipped.&quot;</p><p><a href="https://nooneshappy.com/article/appearing-productive-in-the-workplace/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">No One&#39;s Happy</a> shared how AI lets workers produce expert-looking artifacts without expertise. Thus, two failure modes are reshaping the workplace: elongated slop-filled work where length and formatting no longer signal care, and undetected bad work in unfamiliar domains that quietly erodes judgment.</p><p><a href="https://simonwillison.net/2026/May/6/vibe-coding-and-agentic-engineering/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">Simon Willison</a> on vibe coding meeting agentic engineering: the two are converging faster than he&#39;d like because AI tools are now reliable enough that low-effort prompting often produces shippable code on the first pass, blurring the line between casual experimentation and production work</p><p>A Cat’s Commentary</p><p>That’s all for now.</p><p>P.P.S: Love the newsletter, but only want to get it once per week? Don’t unsubscribe—<a href="https://www.theneurondaily.com/subscribe/f5596641-9099-4045-9641-731cd9fdcf90/preferences?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-gpt-realtime-2-is-coming-for-call-center" target="_blank" rel="noreferrer">update your preferences here</a>.</p><hr>',90)])])}const d=t(n,[["render",i]]);export{h as __pageData,d as default};
